final:
module RefModule(
  input clk,
  input rst_n,
  output reg [3:0] gray
);

  reg [3:0] obf_binary_count;

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      obf_binary_count <= 4'b0;
      gray <= 4'b0;
    end
    else begin
      obf_binary_count <= obf_binary_count + 1;
      gray <= obf_binary_count ^ (obf_binary_count >> 1);
    end
  end

endmodule
